class Solution:
    def clumsy(self, n):
        nums = list(range(n, 0, -1))
        ops = ['*', '/', '+', '-']
        stack = [nums[0]]
        i = 1
        op_i = 0
        while i < len(nums):
            op = ops[op_i % 4]
            if op == '*':
                stack.append(stack.pop() * nums[i])
            elif op == '/':
                a = stack.pop()
                stack.append(int(a / nums[i]))
            elif op == '+':
                stack.append(nums[i])
            else:
                stack.append(-nums[i])
            op_i += 1
            i += 1
        return sum(stack)

